#nullable enable // autogenerated

using System.Collections.Generic;
using MVZ2.GameContent.Buffs;
using MVZ2.GameContent.Detections;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Resources;
using PVZEngine;
using PVZEngine.Auras;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Level;
using UnityEngine;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEffectNames.psychicShackle)]
    public class PsychicShackle : EffectBehaviour
    {
        public PsychicShackle(string nsp, string name) : base(nsp, name)
        {
            AddAura(new ShackleAura());
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            UpdateUnlock(entity);

            entity.SetModelProperty("ShadowSprite", GetShadowSprite(entity));
        }
        private SpriteReference? GetShadowSprite(Entity entity)
        {
            var id = GetRequiredEntityID(entity);
            if (id == null)
                return null;
            var spriteID = new NamespaceID(id.SpaceName, $"model_icon/entity.{id.Path}");
            var spriteRef = new SpriteReference(spriteID);
            return spriteRef;
        }
        private void UpdateUnlock(Entity entity)
        {
            var grid = entity.GetGrid();
            if (grid != null)
            {
                var id = GetRequiredEntityID(entity);
                if (id == null)
                    return;
                foreach (var ent in grid.GetEntities())
                {
                    if (ent.IsEntityOf(id))
                    {
                        entity.PlaySound(VanillaSoundID.chainsBreak);
                        entity.Remove();
                        return;
                    }
                }
            }
        }
        public static Entity? Spawn(LevelEngine level, Vector3 position, NamespaceID requiredID, Entity? source)
        {
            var param = new SpawnParams();
            param.SetProperty(PROP_REQUIRED_ENTITY_ID, requiredID);
            return level.Spawn(VanillaEffectID.psychicShackle, position, source, param);
        }
        public static NamespaceID? GetRequiredEntityID(Entity entity) => entity.GetProperty<NamespaceID>(PROP_REQUIRED_ENTITY_ID);
        public static void SetRequiredEntityID(Entity entity, NamespaceID? value) => entity.SetProperty(PROP_REQUIRED_ENTITY_ID, value);
        public static readonly VanillaEntityPropertyMeta<NamespaceID> PROP_REQUIRED_ENTITY_ID = new VanillaEntityPropertyMeta<NamespaceID>("required_entity_id");
        public class ShackleAura : AuraEffectDefinition
        {
            public ShackleAura() : base(VanillaBuffID.Contraption.psychicShackled, 4)
            {
            }

            public override void GetAuraTargets(AuraEffect auraEffect, List<IBuffTarget> results)
            {
                var source = auraEffect?.Source?.GetEntity();
                if (source == null)
                    return;

                detectBuffer.Clear();
                detector.DetectEntities(source, detectBuffer);
                foreach (var other in detectBuffer)
                {
                    results.Add(other);
                }
            }
            public Detector detector = new BoxDetector(new Vector3(200, 80, 200), Vector3.zero, true)
            {
                factionTarget = FactionTarget.Any,
                mask = EntityCollisionHelper.MASK_PLANT,
            };
            private List<Entity> detectBuffer = new List<Entity>();
        }
    }
}